import React from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

function App() {
  const gold = '#D4AF37'; // Classic Luxury Gold

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', margin: 0, padding: 0, fontFamily: 'Arial, sans-serif' }}>
      
      {/* 1. COMPACT NAVIGATION (LOGO & MENU CLOSE TOGETHER) */}
      <nav style={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center', 
        padding: '20px 50px', 
        backgroundColor: '#000', 
        borderBottom: '1px solid #1a1a1a',
        position: 'sticky',
        top: 0,
        zIndex: 1000
      }}>
        {/* BIGGER, MORE VISIBLE LOGO */}
        <div style={{ display: 'flex', alignItems: 'center' }}>
          <img src={Logo} alt="Àmí by T" style={{ 
            height: '100px', // Increased size for visibility
            width: 'auto',
            filter: 'contrast(125%) brightness(115%)',
            mixBlendMode: 'screen'
          }} />
        </div>

        {/* MENU CATEGORIES (TIGHTER SPACING TO LOGO) */}
        <div style={{ display: 'flex', gap: '40px' }}>
          {['Home', 'Small Chops', 'Office Lunch', 'About Us'].map((item) => (
            <a key={item} href={`#${item.toLowerCase().replace(' ', '')}`} style={{ 
              color: '#fff', 
              textDecoration: 'none', 
              fontSize: '0.9rem', 
              fontWeight: '500',
              letterSpacing: '1px',
              textTransform: 'uppercase'
            }}>
              {item}
            </a>
          ))}
        </div>

        {/* GOLD CART BUTTON */}
        <div style={{ 
          backgroundColor: gold, 
          color: '#000', 
          padding: '10px 25px', 
          borderRadius: '2px', 
          fontSize: '0.8rem', 
          fontWeight: 'bold',
          cursor: 'pointer'
        }}>
          0 ITEMS
        </div>
      </nav>

      {/* 2. THE MAIN CONTENT (STACKED VERTICALLY) */}
      <main>
        {/* TOP SPACING TO REMOVE THE GIANT HEADER GAP */}
        <div style={{ paddingTop: '40px' }}>
          {/* SMALL CHOPS SECTION */}
          <Menu />
          
          {/* CLEAN DIVIDER */}
          <hr style={{ border: '0', height: '1px', backgroundColor: '#1a1a1a', width: '80%', margin: '60px auto' }} />
          
          {/* LUNCH SECTION */}
          <Lunch />
        </div>
      </main>

      {/* 3. FOOTER */}
      <footer style={{ textAlign: 'center', padding: '80px 40px', color: '#333', fontSize: '0.7rem' }}>
        <p style={{ letterSpacing: '4px', color: gold }}>ÀMÍ BY T | LAGOS</p>
        <p style={{ marginTop: '10px' }}>© 2026 ALL RIGHTS RESERVED</p>
      </footer>

    </div>
  );
}

export default App;
